interface TaskStore {
  tasks: Task[];
  addTask: (task: Omit<Task, 'id' | 'position'>) => void;
  updateTask: (id: string, updates: Partial<Task>) => void;
  deleteTask: (id: string) => void;
  reorderTasks: (status: Task['status'], fromIndex: number, toIndex: number) => void;
}

reorderTasks: (status, fromIndex, toIndex) =>
  set((state) => {
    const columnTasks = state.tasks
      .filter((t) => t.status === status)
      .sort((a, b) => a.position - b.position);
    const otherTasks = state.tasks.filter((t) => t.status !== status);
    const [moved] = columnTasks.splice(fromIndex, 1);
    columnTasks.splice(toIndex, 0, moved);
    const reordered = columnTasks.map((t, i) => ({ ...t, position: i }));
    return { tasks: [...otherTasks, ...reordered] };
  }),

import React, { useCallback, useRef } from 'react';
import { Task, Column } from '../store/types';
import { TaskCard } from './TaskCard';
import { useTaskStore } from '../store/taskStore';

interface KanbanColumnProps {
  column: Column;
  tasks: Task[];
}

export const KanbanColumn: React.FC<KanbanColumnProps> = ({ column, tasks }) => {
  const reorderTasks = useTaskStore((s) => s.reorderTasks);
  const dragItem = useRef<number | null>(null);
  const sorted = [...tasks].sort((a, b) => a.position - b.position);

  const handleDragStart = useCallback((index: number) => {
    dragItem.current = index;
  }, []);

  const handleDrop = useCallback(
    (dropIndex: number) => {
      if (dragItem.current !== null && dragItem.current !== dropIndex) {
        reorderTasks(column.status, dragItem.current, dropIndex);
      }
      dragItem.current = null;
    },
    [column.status, reorderTasks]
  );

  return (
    <div className="kanban-column">
      <h2>{column.title}</h2>
      <div className="task-list">
        {sorted.map((task, index) => (
          <div
            key={task.id}
            draggable
            onDragStart={() => handleDragStart(index)}
            onDragOver={(e) => e.preventDefault()}
            onDrop={() => handleDrop(index)}
          >
            <TaskCard task={task} />
          </div>
        ))}
      </div>
    </div>
  );
};
